408	                .number, .str => {
409	                    this.builder.ensureUnusedCapacity(iter.len * "- ".len);
410	                    var first = true;
411	                    while (try iter.next()) |item| {
412	                        if (item.isUndefined() or item.isSymbol() or item.isFunction()) {
413	                            continue;
414	                        }
415	
416	                        if (!first) {
417	                            this.newline();
