63	    builder: wtf.StringBuilder,
64	    indent: usize,
65	
66	    known_collections: std.AutoHashMap(JSValue, AnchorAlias),
67	    array_item_counter: usize,
68	    prop_names: bun.StringHashMap(usize),
69	
70	    space: Space,
71	
72	    pub const Space = union(enum) {
73	        minified,
74	        number: u32,
75	        str: String,
76	
77	        pub fn init(global: *JSGlobalObject, space_value: JSValue) JSError!Space {
78	            const space = try space_value.unwrapBoxedPrimitive(global);
79	            if (space.isNumber()) {
80	                // Clamp on the float to match the spec's min(10, ToIntegerOrInfinity(space)).
81	                // toInt32() wraps large values and Infinity to 0, which is wrong.
82	                const num_f = space.asNumber();
83	                if (!(num_f >= 1)) return .minified; // handles NaN, -Infinity, 0, negatives
84	                return .{ .number = if (num_f > 10) 10 else @intFromFloat(num_f) };
85	            }
86	
87	            if (space.isString()) {
88	                const str = try space.toBunString(global);
89	                if (str.length() == 0) {
90	                    str.deref();
91	                    return .minified;
92	                }
93	                return .{ .str = str };
94	            }
95	
96	            return .minified;
97	        }
98	
99	        pub fn deinit(this: *const Space) void {
100	            switch (this.*) {
101	                .minified => {},
102	                .number => {},
103	                .str => |str| {
104	                    str.deref();
105	                },
106	            }
107	        }
108	    };
109	
110	    const AnchorOrigin = enum {
111	        root,
112	        array_item,
113	        prop_value,
114	    };
115	
116	    const AnchorAlias = struct {
117	        anchored: bool,
118	        used: bool,
119	        name: Name,
120	
121	        pub fn init(origin: ValueOrigin) AnchorAlias {
122	            return .{
123	                .anchored = false,
124	                .used = false,
125	                .name = switch (origin) {
126	                    .root => .root,
127	                    .array_item => .{ .array_item = 0 },
128	                    .prop_value => .{ .prop_value = .{ .prop_name = origin.prop_value, .counter = 0 } },
