    expect(result).toContain("num=42");
  });

  it("stringifies nested object as [section]", () => {
    const result = Bun.INI.stringify({ db: { host: "localhost" } });
    expect(result).toContain("[db]");
    expect(result).toContain("host=localhost");
  });

  it("roundtrips parse → stringify → parse", () => {
    const original = { name: "app", db: { host: "localhost", port: "5432" } };
    const ini = Bun.INI.stringify(original);
    expect(Bun.INI.parse(ini)).toEqual(original);
  });

  it("throws on non-string input", () => {
    expect(() => Bun.INI.parse(null)).toThrow();
    expect(() => Bun.INI.parse(undefined)).toThrow();
  });
});
