632	            ':',
633	            ',',
634	            '[',
635	            ']',
636	            '{',
637	            '}',
638	            '#',
639	            '\'',
640	            '"',
641	            '`',
642	            // starting with whitespace requires quotes
643	            ' ',
644	            '\t',
645	            '\n',
646	            '\r',
