/// Self-contained INI parser.
///
/// Supports:
///   - [section] headers → nested objects
///   - key = value pairs  (= is the separator; whitespace around key/value is trimmed)
///   - Comment lines starting with `;` or `#`
///   - Blank lines (silently skipped)
///
/// All values are strings (INI has no native types).
/// All string slices in ParsedINI point directly into the original source slice,
/// so the source must remain alive for at least as long as the ParsedINI.
/// The slice arrays themselves are allocated with the provided allocator.

pub const INI = struct {
    pub const Entry = struct {
        key: []const u8,
        value: []const u8,
    };

    pub const Section = struct {
        name: []const u8,
        entries: []const Entry,
    };

    pub const ParsedINI = struct {
        /// Key-value pairs that appear before any section header.
        global: []const Entry,
        /// Sections, in order of appearance.
        sections: []const Section,
    };

    pub const ParseError = std.mem.Allocator.Error || error{SyntaxError};

    /// Parse an INI-formatted string.
    ///
    /// The returned `ParsedINI` borrows string slices from `source`; the
    /// Entry/Section arrays themselves are heap-allocated with `allocator`
    /// (typically backed by a caller-owned ArenaAllocator).
    pub fn parse(source: []const u8, allocator: std.mem.Allocator) ParseError!ParsedINI {
        var global_entries: std.ArrayListUnmanaged(Entry) = .{};
        var sections: std.ArrayListUnmanaged(Section) = .{};

        // Current section state — null means we are in the global scope.
        var current_section_name: ?[]const u8 = null;
        var current_entries: std.ArrayListUnmanaged(Entry) = .{};

        var line_iter = std.mem.splitScalar(u8, source, '\n');
        while (line_iter.next()) |raw_line| {
            // Strip \r and surrounding whitespace.
            const line = std.mem.trim(u8, raw_line, " \t\r");

            if (line.len == 0) continue;

            // Comment lines.
            if (line[0] == ';' or line[0] == '#') continue;

            if (line[0] == '[') {
                // Flush the previous section (or start accumulating the first section).
                if (current_section_name) |name| {
                    try sections.append(allocator, .{
                        .name = name,
                        .entries = try current_entries.toOwnedSlice(allocator),
                    });
                    current_entries = .{};
                }

                // Parse the section name between [ and ].
                const close_bracket = std.mem.indexOfScalar(u8, line, ']') orelse
                    return error.SyntaxError;
                current_section_name = std.mem.trim(u8, line[1..close_bracket], " \t");
                continue;
            }

            // Key = value pair.
            if (std.mem.indexOfScalar(u8, line, '=')) |eq_pos| {
                const key = std.mem.trim(u8, line[0..eq_pos], " \t");
                const value = std.mem.trim(u8, line[eq_pos + 1 ..], " \t");

                const entry: Entry = .{ .key = key, .value = value };
                if (current_section_name != null) {
                    try current_entries.append(allocator, entry);
                } else {
                    try global_entries.append(allocator, entry);
                }
                continue;
            }

            // Lines that don't start with [ and have no = are silently ignored
            // (e.g. standalone keys without a value, or unknown syntax).
        }

        // Flush the last open section.
        if (current_section_name) |name| {
            try sections.append(allocator, .{
                .name = name,
                .entries = try current_entries.toOwnedSlice(allocator),
            });
        }

        return .{
            .global = try global_entries.toOwnedSlice(allocator),
            .sections = try sections.toOwnedSlice(allocator),
        };
    }
};

const std = @import("std");

