import { describe, expect, it, test } from "bun:test";

describe("Bun.INI", () => {
  it("exists as a namespace on Bun", () => {
    expect(typeof Bun.INI).toBe("object");
    expect(typeof Bun.INI.parse).toBe("function");
    expect(typeof Bun.INI.stringify).toBe("function");
  });

  describe("parse", () => {
    it("parses global key=value pairs", () => {
      expect(Bun.INI.parse("key=value\nfoo=bar")).toEqual({
        key: "value",
        foo: "bar",
      });
    });

    it("parses a section into a nested object", () => {
      expect(
        Bun.INI.parse(`
[database]
host=localhost
port=5432
`),
      ).toEqual({
        database: {
          host: "localhost",
          port: "5432",
        },
      });
    });

    it("parses mixed global keys and sections", () => {
      expect(
        Bun.INI.parse(`
name=myapp

[server]
host=0.0.0.0
port=8080

[db]
host=localhost
`),
      ).toEqual({
        name: "myapp",
        server: {
          host: "0.0.0.0",
          port: "8080",
        },
        db: {
          host: "localhost",
        },
      });
    });

    it("strips ; comment lines", () => {
      expect(
        Bun.INI.parse(`
; this is a comment
key=value
; another comment
foo=bar
`),
      ).toEqual({ key: "value", foo: "bar" });
    });

    it("strips # comment lines", () => {
      expect(
        Bun.INI.parse(`
# this is a comment
key=value
# another comment
`),
      ).toEqual({ key: "value" });
    });

    it("trims whitespace around keys and values", () => {
      expect(Bun.INI.parse("  key  =  value  ")).toEqual({ key: "value" });
    });

    it("trims whitespace around section names", () => {
      expect(
        Bun.INI.parse(`
[  section  ]
x=1
`),
      ).toEqual({ section: { x: "1" } });
    });

    it("handles empty input", () => {
      expect(Bun.INI.parse("")).toEqual({});
    });

    it("handles only blank lines and comments", () => {
      expect(Bun.INI.parse("\n\n; comment\n# another\n\n")).toEqual({});
    });

    it("handles an empty section", () => {
      expect(Bun.INI.parse("[empty]")).toEqual({ empty: {} });
    });

    it("throws on invalid section (missing ])", () => {
      expect(() => Bun.INI.parse("[broken")).toThrow();
    });

    it("throws for non-string input", () => {
      // @ts-ignore
      expect(() => Bun.INI.parse(42)).toThrow();
    });
  });

  describe("stringify", () => {
    it("stringifies global key=value pairs", () => {
      const result = Bun.INI.stringify({ key: "value", foo: "bar" });
      expect(result).toContain("key=value");
      expect(result).toContain("foo=bar");
    });

    it("stringifies a nested object as a [section] block", () => {
      const result = Bun.INI.stringify({
        database: { host: "localhost", port: "5432" },
      });
      expect(result).toContain("[database]");
      expect(result).toContain("host=localhost");
      expect(result).toContain("port=5432");
    });

    it("puts scalar properties before sections", () => {
      const result = Bun.INI.stringify({
        name: "myapp",
        server: { host: "0.0.0.0" },
      });
      const nameIndex = result.indexOf("name=myapp");
      const sectionIndex = result.indexOf("[server]");
      expect(nameIndex).toBeGreaterThanOrEqual(0);
      expect(sectionIndex).toBeGreaterThan(nameIndex);
    });

    it("returns empty string for empty input", () => {
      expect(Bun.INI.stringify({})).toBe("");
    });

    it("stringifies boolean values", () => {
      const result = Bun.INI.stringify({ enabled: true, disabled: false });
      expect(result).toContain("enabled=true");
      expect(result).toContain("disabled=false");
    });

    it("stringifies numeric values", () => {
      const result = Bun.INI.stringify({ count: 42, ratio: 3.14 });
      expect(result).toContain("count=42");
      expect(result).toContain("ratio=3.14");
    });
  });

  describe("roundtrip", () => {
    it("parse → stringify → parse preserves scalar values", () => {
      const src = "host=localhost\nport=5432\n";
      const parsed = Bun.INI.parse(src);
      const stringified = Bun.INI.stringify(parsed);
      const reparsed = Bun.INI.parse(stringified);
      expect(reparsed).toEqual(parsed);
    });

    it("parse → stringify → parse preserves sections", () => {
      const src = `
host=localhost

[db]
host=pg
port=5432
`;
      const parsed = Bun.INI.parse(src);
      const stringified = Bun.INI.stringify(parsed);
      const reparsed = Bun.INI.parse(stringified);
      expect(reparsed).toEqual(parsed);
    });
  });
});

