1	/// Self-contained INI parser.
2	///
3	/// Supports:
4	///   - [section] headers → nested objects
5	///   - key = value pairs  (= is the separator; whitespace around key/value is trimmed)
6	///   - Comment lines starting with `;` or `#`
7	///   - Blank lines (silently skipped)
8	///
9	/// All values are strings (INI has no native types).
10	/// All string slices in ParsedINI point directly into the original source slice,
11	/// so the source must remain alive for at least as long as the ParsedINI.
12	/// The slice arrays themselves are allocated with the provided allocator.
13	
14	pub const INI = struct {
15	    pub const Entry = struct {
16	        key: []const u8,
17	        value: []const u8,
18	    };
19	
20	    pub const Section = struct {
21	        name: []const u8,
22	        entries: []const Entry,
23	    };
24	
25	    pub const ParsedINI = struct {
26	        /// Key-value pairs that appear before any section header.
27	        global: []const Entry,
28	        /// Sections, in order of appearance.
29	        sections: []const Section,
30	    };
31	
32	    pub const ParseError = std.mem.Allocator.Error || error{SyntaxError};
33	
34	    /// Parse an INI-formatted string.
35	    ///
36	    /// The returned `ParsedINI` borrows string slices from `source`; the
37	    /// Entry/Section arrays themselves are heap-allocated with `allocator`
38	    /// (typically backed by a caller-owned ArenaAllocator).
39	    pub fn parse(source: []const u8, allocator: std.mem.Allocator) ParseError!ParsedINI {
40	        var global_entries: std.ArrayListUnmanaged(Entry) = .{};
41	        var sections: std.ArrayListUnmanaged(Section) = .{};
42	
43	        // Current section state — null means we are in the global scope.
44	        var current_section_name: ?[]const u8 = null;
45	        var current_entries: std.ArrayListUnmanaged(Entry) = .{};
46	
47	        var line_iter = std.mem.splitScalar(u8, source, '\n');
48	        while (line_iter.next()) |raw_line| {
49	            // Strip \r and surrounding whitespace.
50	            const line = std.mem.trim(u8, raw_line, " \t\r");
51	
52	            if (line.len == 0) continue;
53	
54	            // Comment lines.
55	            if (line[0] == ';' or line[0] == '#') continue;
56	
57	            if (line[0] == '[') {
58	                // Flush the previous section (or start accumulating the first section).
59	                if (current_section_name) |name| {
60	                    try sections.append(allocator, .{
61	                        .name = name,
62	                        .entries = try current_entries.toOwnedSlice(allocator),
63	                    });
64	                    current_entries = .{};
65	                }
66	
67	                // Parse the section name between [ and ].
68	                const close_bracket = std.mem.indexOfScalar(u8, line, ']') orelse
69	                    return error.SyntaxError;
70	                current_section_name = std.mem.trim(u8, line[1..close_bracket], " \t");
71	                continue;
72	            }
73	
74	            // Key = value pair.
