/// JS-facing `Bun.INI` namespace object.
///
/// Exposes two functions:
///   Bun.INI.parse(source: string) → object
///   Bun.INI.stringify(value: object) → string
///
/// parse:
///   Global key=value pairs become top-level properties.
///   [section] blocks become nested objects.
///   All values are strings.
///
/// stringify:
///   Top-level primitive values → `key=value\n`
///   Top-level object values    → `[key]\nsubkey=value\n`

pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

// ---------------------------------------------------------------------------
// parse
// ---------------------------------------------------------------------------

pub fn parse(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callframe.argument(0);

    if (input_value.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }

    if (!input_value.isString()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }

    var arena = bun.ArenaAllocator.init(bun.default_allocator);
    defer arena.deinit();
    const allocator = arena.allocator();

    var input_slice = try input_value.toSlice(globalThis, bun.default_allocator);
    defer input_slice.deinit();

    const parsed = INI.parse(input_slice.slice(), allocator) catch |err| switch (err) {
        error.OutOfMemory => return error.OutOfMemory,
        error.SyntaxError => return globalThis.throwValue(
            globalThis.createSyntaxErrorInstance("INI parse error: invalid syntax", .{}),
        ),
    };

    // Build the top-level JS object.
    const result = JSValue.createEmptyObject(globalThis, parsed.global.len + parsed.sections.len);

    // Global key=value pairs.
    for (parsed.global) |entry| {
        const key = ZigString.init(entry.key);
        const val = try bun.String.createUTF8ForJS(globalThis, entry.value);
        result.put(globalThis, &key, val);
    }

    // Section objects.
    for (parsed.sections) |section| {
        const section_obj = JSValue.createEmptyObject(globalThis, section.entries.len);
        for (section.entries) |entry| {
            const key = ZigString.init(entry.key);
            const val = try bun.String.createUTF8ForJS(globalThis, entry.value);
            section_obj.put(globalThis, &key, val);
        }
        const section_key = ZigString.init(section.name);
        result.put(globalThis, &section_key, section_obj);
    }

    return result;
}

// ---------------------------------------------------------------------------
// stringify
// ---------------------------------------------------------------------------

pub fn stringify(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callframe.argument(0);

    if (input_value.isEmptyOrUndefinedOrNull()) {
        return bun.String.createUTF8ForJS(globalThis, "");
    }

    if (!input_value.isObject()) {
        return globalThis.throwInvalidArguments("Bun.INI.stringify: argument must be an object", .{});
    }

    var builder: wtf.StringBuilder = .{};
    defer builder.deinit();

    // Two passes:
    //   1. Scalar (non-object) top-level properties → key=value lines
    //   2. Object top-level properties              → [section] blocks

    // --- Pass 1: scalar values ---
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            globalThis,
            try input_value.toObject(globalThis),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            const val = iter.value;
            if (val.isUndefined() or val.isSymbol() or val.isFunction()) continue;
            // Skip nested objects — they become sections in pass 2.
            if (val.isObject() and !val.isArray()) continue;

            appendKey(&builder, prop_name);
            builder.append(.latin1, "=");
            try appendScalarValue(&builder, globalThis, val);
            builder.append(.latin1, "\n");
        }
    }

    // --- Pass 2: object values become [section] blocks ---
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            globalThis,
            try input_value.toObject(globalThis),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            const val = iter.value;
            if (val.isUndefined() or val.isSymbol() or val.isFunction()) continue;
            if (!val.isObject() or val.isArray()) continue;

            // Section header.
            builder.append(.latin1, "[");
            appendKey(&builder, prop_name);
            builder.append(.latin1, "]\n");

            // Section entries — only scalar (non-object) properties.
            var section_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
                globalThis,
                try val.toObject(globalThis),
            );
            defer section_iter.deinit();

            while (try section_iter.next()) |entry_key| {
                const entry_val = section_iter.value;
                if (entry_val.isUndefined() or entry_val.isSymbol() or entry_val.isFunction()) continue;
                // Deep nesting (object inside a section) is skipped — INI is flat.
                if (entry_val.isObject() and !entry_val.isArray()) continue;

                appendKey(&builder, entry_key);
                builder.append(.latin1, "=");
                try appendScalarValue(&builder, globalThis, entry_val);
                builder.append(.latin1, "\n");
            }
        }
    }

    return builder.toString(globalThis);
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/// Append a property name (bun.String) to the builder as UTF-8.
fn appendKey(builder: *wtf.StringBuilder, key: bun.String) void {
    builder.append(.string, key);
}

/// Append a scalar JS value (string, number, boolean, null) to the builder.
fn appendScalarValue(
    builder: *wtf.StringBuilder,
    globalThis: *jsc.JSGlobalObject,
    value: jsc.JSValue,
) bun.JSError!void {
    if (value.isNull()) {
        builder.append(.latin1, "null");
        return;
    }
    if (value.isBoolean()) {
        builder.append(.latin1, if (value.asBoolean()) "true" else "false");
        return;
    }
    if (value.isInt32()) {
        builder.append(.int, value.asInt32());
        return;
    }
    if (value.isNumber()) {
        builder.append(.double, value.asNumber());
        return;
    }
    // String (and anything else coerced to string).
    const str = try value.toBunString(globalThis);
    defer str.deref();
    builder.append(.string, str);
}

